const raw = $('Loop Over Claimed Events').item.json;
const vlmResponse = $input.first().json;

let description = null;
let notes = null;
try {
  description = vlmResponse.choices?.[0]?.message?.content ?? null;
} catch (err) {
  notes = String(err);
}

return [{
  json: {
    raw_event_id: raw.id,
    description,
    notes,
  },
}];

const raw = $('Loop Over Claimed Events').item.json;
const response = $input.first().json;

let parsed = {};
try {
  const text = response.choices?.[0]?.message?.content ?? '';
  const match = text.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {};
} catch (err) {
  parsed = { _parse_error: String(err) };
}

// Defensive against the model ignoring the "ONLY the plate's characters" instruction and
// writing a narrative explanation into plate_text instead (seen in real data -- prompt wording
// alone doesn't guarantee compliance). A clean short token passes through as-is; anything with
// whitespace/newlines or over 15 chars gets the most plate-like token pulled out of it instead.
function sanitizePlate(text) {
  if (!text) return null;
  const trimmed = String(text).trim();
  if (!trimmed) return null;
  if (!/\s/.test(trimmed) && trimmed.length <= 15) return trimmed;
  const tokens = trimmed.match(/[A-Z0-9-]{4,14}/g);
  return tokens ? tokens[tokens.length - 1] : trimmed;
}

return [{
  json: {
    raw_event_id: raw.id,
    color: parsed.color ?? null,
    body_type: parsed.body_type ?? null,
    make_guess: parsed.make ?? null,
    make_confidence: parsed.make_confidence ?? null,
    model_guess: parsed.model ?? null,
    model_confidence: parsed.model_confidence ?? null,
    notable_features: parsed.notable_features ?? null,
    plate_text_llm: sanitizePlate(parsed.plate_text),
    plate_text_frigate: raw.sub_label ?? null,
    plate_confidence: null,
    notes: parsed._parse_error ?? null,
  },
}];
